noncompliant.code:
resource "google_logging_project_exclusion" "bad_example" {
  name        = "exclude-admins"
  description = "Exclude admin group from audit logs"
  filter      = "resource.type="gce_instance" AND protoPayload.authenticationInfo.principalEmail:admin@myorg.com"
  project     = "my-project"
}

compliant.code:
# No exclusions for users or groups
resource "google_logging_project_exclusion" "none" {
  count = 0
}
